from openai import OpenAI
client = OpenAI()

# Una imagen de un flowchart
image_url = "https://www.process.st/flowchart.png"

response = client.chat.completions.create(
    model="gpt-4o",
    messages=[
        {
            "role": "user",
            "content": [
                {"type": "text", "text": "Explica este diagrama de flujo"},
                {"type": "image_url", "image_url": {"url": image_url}}
            ]
        }
    ]
)
print(response.choices[0].message.content)

